def create_or_update_user(nameid, attributes):
    username = nameid
    
    email = attributes.get('email', attributes.get('mail', ''))
    first_name = attributes.get('firstName', attributes.get('givenName', ''))
    last_name = attributes.get('lastName', attributes.get('surname', attributes.get('sn', '')))
    
    if isinstance(email, list):
        email = email[0] if email else ''
    if isinstance(first_name, list):
        first_name = first_name[0] if first_name else ''
    if isinstance(last_name, list):
        last_name = last_name[0] if last_name else ''
    
    username_hash = hashlib.md5(username.encode()).hexdigest()[:30]
    
    try:
        user = User.objects.get(username=username_hash)
        user.email = email
        user.first_name = first_name[:30]
        user.last_name = last_name[:30]
        user.save()
    except User.DoesNotExist:
        user = User.objects.create_user(
            username=username_hash,
            email=email,
            first_name=first_name[:30],
            last_name=last_name[:30]
        )
    
    return user


