def saml_acs(request):
    saml_response_b64 = request.POST.get('SAMLResponse')
    relay_state = request.POST.get('RelayState', '/')
    
    if not saml_response_b64:
        return HttpResponse('Missing SAMLResponse', status=400)
    
    saml_response = SAMLResponse(saml_response_b64)
    
    if not saml_response.decode_response():
        return HttpResponse('Invalid SAML Response encoding', status=400)
    
    if not saml_response.validate_structure():
        return HttpResponse('Invalid SAML Response structure', status=400)
    
    if not saml_response.is_success():
        return HttpResponse('SAML Authentication failed', status=401)
    
    nameid = saml_response.extract_nameid()
    if not nameid:
        return HttpResponse('Missing NameID in SAML Response', status=400)
    
    attributes = saml_response.extract_attributes()
    session_index = saml_response.extract_session_index()
    
    user = create_or_update_user(nameid, attributes)
    
    user.backend = 'django.contrib.auth.backends.ModelBackend'
    login(request, user)
    
    request.session['saml_nameid'] = nameid
    request.session['saml_session_index'] = session_index
    request.session['saml_attributes'] = attributes
    
    return HttpResponseRedirect(relay_state)


